import { LineChart } from '@tale-ui/charts/line-chart';

const data = [
  { week: 'Week 1', visitors: 2400 },
  { week: 'Week 2', visitors: 3100 },
  { week: 'Week 3', visitors: 2800 },
  { week: 'Week 4', visitors: 4200 },
  { week: 'Week 5', visitors: 3900 },
];

export function Example() {
  return (
    <LineChart.Root data={data} width={600} height={300}>
      <LineChart.Grid />
      <LineChart.XAxis dataKey="week" />
      <LineChart.YAxis />
      <LineChart.Tooltip />
      <LineChart.Line dataKey="visitors" />
    </LineChart.Root>
  );
}
